import 'dart:async'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../core/di/injection.dart'; import '../../../auth/presentation/providers/auth_providers.dart'; import '../../../product/domain/entities/product.dart'; import '../../domain/entities/recent_search.dart'; import '../../domain/entities/trending_search.dart'; import '../../domain/models/search_filter.dart'; import '../../domain/repositories/search_repository.dart';
final searchRepositoryProvider=Provider<SearchRepository>((ref)=>sl<SearchRepository>()); final searchFilterProvider=StateProvider<SearchFilter>((ref)=>const SearchFilter()); final searchResultsProvider=FutureProvider<List<Product>>((ref)=>ref.watch(searchRepositoryProvider).searchProducts(filter:ref.watch(searchFilterProvider))); final recentSearchesProvider=StreamProvider<List<RecentSearch>>((ref){final user=ref.watch(currentUserProvider); if(user==null)return const Stream.empty(); return ref.watch(searchRepositoryProvider).watchRecentSearches(userId:user.uid);}); final trendingSearchesProvider=FutureProvider<List<TrendingSearch>>((ref)=>ref.watch(searchRepositoryProvider).getTrendingSearches()); final searchControllerProvider=StateNotifierProvider<SearchController,SearchControllerState>((ref)=>SearchController(ref));
class SearchController extends StateNotifier<SearchControllerState>{final Ref ref; Timer? debounce; SearchController(this.ref):super(const SearchControllerState()); void updateKeyword(String keyword){debounce?.cancel(); debounce=Timer(const Duration(milliseconds:350),(){ref.read(searchFilterProvider.notifier).state=ref.read(searchFilterProvider).copyWith(keyword:keyword); ref.invalidate(searchResultsProvider);});} Future<void> submitSearch(String keyword) async{final user=ref.read(currentUserProvider); ref.read(searchFilterProvider.notifier).state=ref.read(searchFilterProvider).copyWith(keyword:keyword); if(user!=null) await ref.read(searchRepositoryProvider).saveRecentSearch(userId:user.uid,keyword:keyword); ref.invalidate(searchResultsProvider);} @override void dispose(){debounce?.cancel(); super.dispose();}}
class SearchControllerState{final bool isLoading; final String? errorMessage; const SearchControllerState({this.isLoading=false,this.errorMessage});}
